package fence

import (
	"strings"
	"testing"
)

func TestUntrusted_NeutralizesSentinelExactlyAndPreservesCase(t *testing.T) {
	// Craft content that itself contains the exact sentinel plus mixed-case text.
	content := "Hello WORLD " + sentinel + " tail text"

	result := Untrusted("label", "prov", content)

	// The wrapping itself introduces exactly 4 sentinel occurrences (open x2, close x2
	// per the format string: sentinel appears 4 times total in the template).
	// Count how many sentinel occurrences exist in the template with empty content.
	baseline := Untrusted("label", "prov", "")
	wantCount := strings.Count(baseline, sentinel)

	gotCount := strings.Count(result, sentinel)
	if gotCount != wantCount {
		t.Fatalf("sentinel occurrences in result = %d, want %d (content sentinel was not neutralized; forged/duplicate fence tokens present)", gotCount, wantCount)
	}

	// The neutralization must produce the replacement marker for the embedded sentinel.
	if !strings.Contains(result, "[fence-token-removed]") {
		t.Fatalf("expected neutralized marker [fence-token-removed] in result, got: %q", result)
	}

	// Case of surrounding content must be preserved; a case-insensitive/lowercasing
	// neutralization implementation would corrupt "WORLD" into "world".
	if !strings.Contains(result, "WORLD") {
		t.Fatalf("expected original mixed-case content to be preserved, got: %q", result)
	}
	if strings.Contains(result, "world ") {
		t.Fatalf("content appears to have been lower-cased, indicating broken neutralization: %q", result)
	}
}
